#include <stdio.h>
#include <stdlib.h>
#define INF 1000000000
#define MAX 100000

// Structure to represent a graph edge
typedef struct Edge {
    int src, dest, weight;
} Edge;

// Structure to represent a graph
typedef struct Graph {
    int V, E;
    Edge* edge;
} Graph;

// Function to create a graph
Graph* createGraph(int V, int E) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;    graph->E = E;
    graph->edge = (Edge*) malloc(E * sizeof(Edge));
    return graph;
}

// Function to find the Minimum Spanning Tree of a graph
int spanningTree(Graph* graph) {
    int* parent = (int*) malloc(graph->V * sizeof(int));
    int* key = (int*) malloc(graph->V * sizeof(int));
    int* mstSet = (int*) malloc(graph->V * sizeof(int));

    for (int i = 0; i < graph->V; i++) {
        key[i] = INF;
        mstSet[i] = 0;
    }

    key[0] = 0;
    parent[0] = -1;

    for (int i = 0; i < graph->V; i++) {
        int u = -1;
        for (int v = 0; v < graph->V; v++) {
            if (mstSet[v] == 0 && key[v] < INF) {
                u = v;
                break;
            }
        }

        mstSet[u] = 1;

        for (int v = 0; v < graph->V; v++) {
            int weight = 0;
            for (int j = 0; j < graph->E; j++) {
                if (graph->edge[j].src == u && graph->edge[j].dest == v) {
                    weight = graph->edge[j].weight;
                    break;
                }
            }

            if (weight > 0 && mstSet[v] == 0 && weight < key[v]) {
                parent[v] = u;
                key[v] = weight;
            }
        }
    }

    int sum = 0;
    for (int i = 1; i < graph->V; i++) {
        sum += key[i];
    }

    free(parent);
    free(key);
    free(mstSet);

    return sum;
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);

    Graph* graph = createGraph(V, E);

    for (int i = 0; i < E; i++) {
        scanf("%d %d %d", &graph->edge[i].src, &graph->edge[i].dest, &graph->edge[i].weight);
    }

    int sum = spanningTree(graph);
    printf("%d\n", sum);

    free(graph->edge);
    free(graph);

    return 0;
}

