class Solution {
    spanningTree(V, adj) {
        let pq = [];
        let vis = new Array(V).fill(0);
        pq.push([0, 0]);
        let sum = 0;
        while (pq.length > 0) {
            let [wt, node] = pq.shift();
            if (vis[node] === 1) continue;
            vis[node] = 1;
            sum += wt;
            for (let i = 0; i < adj[node].length; i++) {
                let [adjNode, edW] = adj[node][i];
                if (vis[adjNode] === 0) {
                    pq.push([edW, adjNode]);
                    pq.sort((a, b) => a[0] - b[0]);
                }
            }
        }
        return sum;
    }
}

